@startuml
' UML diagram for "Switch文を使ったCeilingFan"

package "Switch文を使ったCeilingFan" {
  package "dirty" {
    class App {
      - STDIN : Scanner {readOnly}
      - MSG_PRESS_ENTER : String {readOnly}
      - BREAK_LINE : String {readOnly}
      + main(String... args) : void
      - spendLife(CeilingFanPullChain chain) : void
      - show(String message) : void
      - recieveInputtedEnterKey() : String
    }

    class CeilingFanPullChain {
      - currentState : Speed
      + CeilingFanPullChain()
      + pull() : void
    }

    class Speed {
      - nameJa : String {readOnly}
      - Speed(String nameJa)
      + nameJa() : String
      + showNameJa() : void
    }
  }
}

App ..> CeilingFanPullChain : use
CeilingFanPullChain ..> Speed : call

@enduml
